import React, { useState } from 'react';
import { Progress } from 'antd';
import 'antd/dist/reset.css';

const getStrength = (password) => {
  let strength = 0;
  if (password.length >= 8) strength += 20;
  if (/[A-Z]/.test(password)) strength += 20;
  if (/[a-z]/.test(password)) strength += 20;
  if (/[0-9]/.test(password)) strength += 20;
  if (/[^A-Za-z0-9]/.test(password)) strength += 20;
  return strength;
};

const getFeedback = (score) => {
  if (score <= 30) return {
    msg: "Oops! That password is way too weak. Try mixing in uppercase letters, numbers, and symbols to pack a punch!",
    imgPath: "/images/password/0.png"
  };
  if (score <= 50) return {
    msg: "Getting there! Add more characters and avoid using names or birthdays to make it harder to crack.",
    imgPath: "/images/password/1.png"
  };
  if (score <= 70) return {
    msg: "Nice! That's a solid hit. Use longer phrases or mix random words with symbols for even stronger protection.",
    imgPath: "/images/password/2.png"
  };
  if (score < 100) return {
    msg: "So close! Just a few more characters or a little more randomness and your password will be unstoppable.",
    imgPath: "/images/password/3.png"
  };
  return {
    msg: "🎉 Game over for the beaster! That's what I call a legendary password!\nYou just outsmarted 90% of internet users. Respect!",
    imgPath: "/images/password/4.png"
  };
};

const PasswordPractice = () => {
  const [password, setPassword] = useState('');
  const score = getStrength(password);
  const feedback = getFeedback(score);

  return (
    <div style={styles.container}>
      <h2 style={styles.header}>🔐 Password Practice</h2>

      <div style={styles.bubble}>
        <span style={styles.bot}>🤖</span> Hey, let's play a little game!<br />
        Enter the password you created below to defeat the monster!<br />
        The stronger your password is, the easier you will win.
      </div>

      <input
        type="password"
        placeholder="Please enter the password"
        value={password}
        onChange={(e) => setPassword(e.target.value)}
        style={styles.input}
      />

      <div style={styles.bubble}>
        <span style={styles.bot}>🤖</span> Your password strength is {score}%:
      </div>

      <Progress percent={score} strokeColor={{ from: '#108ee9', to: '#ffe100' }} status="active" />

      <img src={feedback.imgPath} alt="monster" style={styles.image} />

      <div style={styles.bubble}>
        <span style={styles.bot}>🤖</span> {feedback.msg}
      </div>
    </div>
  );
};

const styles = {
  container: {
    padding: '1.2em',
    fontFamily: 'Arial',
    maxWidth: '500px',
    margin: '0 auto',
    background: 'linear-gradient(to bottom right, #e0f7fa, #f3f5f7)',
    borderRadius: '12px',
    minHeight: '100vh'
  },
  header: {
    textAlign: 'center',
    color: '#333',
    marginBottom: '1.5em'
  },
  input: {
    width: '100%',
    padding: '1em',
    margin: '1em 0',
    fontSize: '1em',
    borderRadius: '12px',
    border: '1px solid #ccc',
    backgroundColor: '#fff'
  },
  bubble: {
    backgroundColor: '#f0f8ff',
    padding: '1em',
    margin: '1em 0',
    borderRadius: '12px',
    border: '1px solid #b0c4de',
    whiteSpace: 'pre-wrap'
  },
  bot: {
    fontWeight: 'bold',
    marginRight: '0.5em'
  },
  image: {
    width: '100%',
    maxWidth: '260px',
    display: 'block',
    margin: '1.5em auto'
  }
};

export default PasswordPractice;
